// Transform Jira issues to ALDECI format
const timestamp = new Date().toISOString();
const findings = [];

for (const issue of $input.all()) {
  const jiraIssue = issue.json;

  findings.push({
    finding_id: `jira-${jiraIssue.key}`,
    finding_type: 'security_issue',
    entity_type: 'issue',
    entity_id: jiraIssue.key,
    title: jiraIssue.fields?.summary || 'Untitled',
    description: jiraIssue.fields?.description?.content?.[0]?.content?.[0]?.text || '',
    severity: (() => {
      const priority = jiraIssue.fields?.priority?.name?.toLowerCase() || 'medium';
      if (priority.includes('critical')) return 'critical';
      if (priority.includes('highest') || priority.includes('high')) return 'high';
      if (priority.includes('medium')) return 'medium';
      if (priority.includes('low')) return 'low';
      return 'info';
    })(),
    status: (() => {
      const status = jiraIssue.fields?.status?.name?.toLowerCase() || 'open';
      if (status === 'done' || status === 'closed') return 'closed';
      if (status === 'in progress' || status === 'reviewing') return 'verified';
      return 'open';
    })(),
    source: 'jira',
    scanner: 'jira-security-sync',
    discovery_time: timestamp,
    jira_key: jiraIssue.key,
    jira_url: jiraIssue.self,
    assignee: jiraIssue.fields?.assignee?.displayName,
    reporter: jiraIssue.fields?.reporter?.displayName,
    project: jiraIssue.fields?.project?.key,
    project_name: jiraIssue.fields?.project?.name,
    labels: jiraIssue.fields?.labels || [],
    components: jiraIssue.fields?.components?.map(c => c.name) || [],
    created_at: jiraIssue.fields?.created,
    updated_at: jiraIssue.fields?.updated,
    due_date: jiraIssue.fields?.duedate,
    custom_fields: (() => {
      const custom = {};
      for (const [key, value] of Object.entries(jiraIssue.fields || {})) {
        if (key.startsWith('customfield_')) {
          custom[key] = value;
        }
      }
      return custom;
    })()
  });
}

return { items: findings };

// Transform ALDECI findings to Jira issue format
const findings = [];

for (const item of $input.all()) {
  const aldeciFinding = item.json;

  // Map severity to Jira priority
  const priorityMap = {
    critical: 'Highest',
    high: 'High',
    medium: 'Medium',
    low: 'Low',
    info: 'Lowest'
  };

  findings.push({
    fields: {
      project: {
        key: process.env.JIRA_PROJECT_KEY || 'SEC'
      },
      summary: aldeciFinding.title || `Security Finding: ${aldeciFinding.finding_id}`,
      description: {
        version: 3,
        type: 'doc',
        content: [
          {
            type: 'paragraph',
            content: [
              {
                type: 'text',
                text: aldeciFinding.description || ''
              }
            ]
          },
          {
            type: 'paragraph',
            content: [
              {
                type: 'text',
                text: `Source: ${aldeciFinding.source || 'ALDECI'}\nSeverity: ${aldeciFinding.severity}\nFinding ID: ${aldeciFinding.finding_id}`
              }
            ]
          }
        ]
      },
      issuetype: {
        name: 'Security Issue'
      },
      priority: {
        name: priorityMap[aldeciFinding.severity] || 'Medium'
      },
      labels: [
        'security',
        'aldeci-import',
        aldeciFinding.source || 'external'
      ],
      customfield_10001: aldeciFinding.finding_id,
      customfield_10002: aldeciFinding.source,
      duedate: (() => {
        const today = new Date();
        const daysOut = aldeciFinding.severity === 'critical' ? 1 : 
                       aldeciFinding.severity === 'high' ? 3 : 7;
        const due = new Date(today.getTime() + daysOut * 24 * 60 * 60 * 1000);
        return due.toISOString().split('T')[0];
      })()
    }
  });
}

return { items: findings };

// Determine if issue exists in Jira based on finding_id
// This would check against Jira search results
return {
  items: $input.all().map(item => ({
    ...item.json,
    jira_issue_exists: false  // Would be populated by actual Jira query
  }))
};
